const HANDLES = [
  // AI labs / foundation models
  'OpenAI','AnthropicAI','GoogleDeepMind','MistralAI','xai','Meta','nvidia','CohereAI','Adept',
  // Founders / researchers
  'sama','ylecun','DarioAmodei','karpathy','demishassabis','sundarpichai','satyanadella','drjimfan',
  // Business / enterprise AI
  'perplexity_ai','cursor_ai','harvey__ai','glean','writer','jasper_ai','notion','zapier','n8n_io','replit','cognition_labs','SierraAI','readdotai','hippocratic_ai',
  // Dev / coding AI
  'github','lovable_dev','bolt_new','v0',
  // Video AI
  'runwayml','LumaLabsAI','Kling_ai','KLING_AI','midjourney','HeyGen_Official','pika_labs','HailuoAI_MiniMax','GenmoAI','sync_so','captions_AI',
  // Audio / music AI
  'suno_ai_','ElevenLabsIO','udiomusic',
  // Image AI
  'StabilityAI','blackforestlabs','ideogram_ai','leonardoai_',
  // News / analysts
  'rowancheung','AndrewYNg','emollick'
];

const handlesList = HANDLES.join(', @');
// Fixed 24-hour window — dedupe handles duplicates
const since = new Date(Date.now() - 24*3600*1000).toISOString().slice(0,16);

const instruction = `Найди ЗНАЧИМЫЕ AI-новости за последние 24 часа (с ${since}) от X-аккаунтов: @${handlesList}. Интересуют ТОЛЬКО:\n- новые релизы моделей (видео, аудио, изображения, LLM)\n- новые фичи и обновления ИИ-инструментов\n- анонсы продуктов\n- значимые технические демо\n\nИгнорируй:\n- личные мнения без релиза\n- мемы, шутки\n- рекламу событий без продукта\n- общие размышления\n\nДля каждой найденной новости сделай web-поиск чтобы добрать контекст (что это за продукт, ссылки, цена, дата).\n\nВерни СТРОГО JSON: {\n  "posts": [\n    {\n      "headline": "короткий заголовок до 80 символов",\n      "source": "@handle",\n      "source_url": "ссылка на X-пост",\n      "summary": "2-3 предложения: что произошло, какие возможности",\n      "why_relevant": "1 предложение почему это важно (применение в бизнесе/автоматизации или в работе с видео/картинками/аудио, в зависимости от типа новости)",\n      "extra_links": ["опциональные доп.ссылки на блог/сайт"]\n    }\n  ]\n}\n\nСтарайся найти 2-4 значимых новости. Если действительно ничего нет — {"posts": []}.`;

const body = JSON.stringify({
  model: 'grok-4-fast-reasoning',
  input: instruction,
  tools: [
    { type: 'web_search' },
    { type: 'x_search' }
  ]
});

return [{ json: { body } }];

const data = $input.first().json;
const output = data.output || [];

let jsonText = '';
for (const o of output) {
  if (o.type === 'message' && Array.isArray(o.content)) {
    for (const c of o.content) {
      if (c.type === 'output_text' && c.text) {
        jsonText = c.text;
        break;
      }
    }
  }
  if (jsonText) break;
}

if (!jsonText) return [];

jsonText = jsonText.replace(/```json\s*/g, '').replace(/```\s*$/g, '').trim();

let parsed;
try { parsed = JSON.parse(jsonText); } catch(e) { return []; }

const posts = parsed.posts || [];
if (!posts.length) return [];

// Normalize headline for robust dedupe: lowercase, strip punctuation/extra spaces, first 40 chars
function normalize(s) {
  return (s || '').toLowerCase()
    .replace(/[^a-zа-я0-9\s]/gi, ' ')
    .replace(/\s+/g, ' ')
    .trim()
    .slice(0, 40);
}

const store = $getWorkflowStaticData('global');
if (!store.sentGrokPosts) store.sentGrokPosts = [];
const sentSet = new Set(store.sentGrokPosts);

const seenInRun = new Set();
const fresh = [];
for (const p of posts) {
  if (!p.headline) continue;
  const key = normalize(p.headline);
  if (!key || key.length < 5) continue;
  if (sentSet.has(key) || seenInRun.has(key)) continue;
  seenInRun.add(key);
  fresh.push(p);
  store.sentGrokPosts.push(key);
}

if (store.sentGrokPosts.length > 300) store.sentGrokPosts = store.sentGrokPosts.slice(-300);

return fresh.map(p => ({ json: p }));

const res = $input.first().json;
// Claude API returns content array
let post = '';
if (res.content && Array.isArray(res.content)) {
  const textBlock = res.content.find(c => c.type === 'text');
  post = textBlock?.text?.trim() || '';
} else if (res.choices) {
  post = res.choices?.[0]?.message?.content?.trim() || '';
}
post = post.replace(/@studiyaCHE\s*$/i, '').trim();
post += '\n\n@studiyaCHE';
const id = 'grok_' + Date.now() + '_' + Math.random().toString(36).slice(2,7);
return [{ json: { post, id } }];
